      "content": "const express = require('express');
const service = require('./service');
const { sendError } = require('../../lib/errors');

const router = express.Router({ mergeParams: true });

router.post('/', (req, res) => {
  const { message } = req.body;
  if (!message) {
    return sendError(res, 400, 'INVALID_PAYLOAD', 'Message is required');
  }

  const comment = service.createComment(req.params.projectId, req.params.taskId, message);
  if (!comment) {
    return sendError(res, 404, 'NOT_FOUND', 'Project or task not found');
  }

  res.status(201).json({ comment });
});

router.get('/', (req, res) => {
  const comments = service.getComments(req.params.projectId, req.params.taskId);
  if (!comments) {
    return sendError(res, 404, 'NOT_FOUND', 'Project or task not found');
  }

  res.json({ comments });
});

module.exports = router;
