      "path": "src/modules/comments/service.js",
      "content": "const { generateId } = require('../../lib/id');
const projectsService = require('../projects/service');

const commentsStore = {};

function createComment(projectId, taskId, message) {
  const project = projectsService.getProjectById(projectId);
  if (!project || !project.tasks[taskId]) {
    return null;
  }

  const commentId = generateId();
  const comment = { id: commentId, message };

  if (!commentsStore[projectId]) {
    commentsStore[projectId] = {};
  }
  if (!commentsStore[projectId][taskId]) {
    commentsStore[projectId][taskId] = [];
  }

  commentsStore[projectId][taskId].push(comment);
  return comment;
}

function getComments(projectId, taskId) {
  const project = projectsService.getProjectById(projectId);
  if (!project || !project.tasks[taskId]) {
    return null;
  }

  return commentsStore[projectId][taskId] || [];
}

module.exports = { createComment, getComments };
