      "path": "src/modules/tasks/routes.js",
      "content": "const express = require('express');
const service = require('./service');
const { sendError } = require('../../lib/errors');

const router = express.Router({ mergeParams: true });

router.post('/', (req, res) => {
  const task = service.createTask(req.params.projectId);
  if (!task) {
    return sendError(res, 404, 'NOT_FOUND', 'Project not found');
  }

  res.status(201).json({ task });
});

router.get('/', (req, res) => {
  const tasks = service.getTasks(req.params.projectId);
  if (!tasks) {
    return sendError(res, 404, 'NOT_FOUND', 'Project not found');
  }

  let filteredTasks = Object.values(tasks);
  const status = req.query.status;
  if (status) {
    filteredTasks = filteredTasks.filter(task => task.status === status);
  }

  res.json({ tasks: filteredTasks });
});

router.patch('/:taskId', (req, res) => {
  const { status } = req.body;
  const task = service.updateTask(req.params.projectId, req.params.taskId, status);
  if (!task) {
    return sendError(res, 404, 'NOT_FOUND', 'Project or task not found');
  }

  res.json({ task });
});

module.exports = router;
