      "content": "const { generateId } = require('../../lib/id');
const projectsService = require('../projects/service');

function createTask(projectId) {
  const project = projectsService.getProjectById(projectId);
  if (!project) {
    return null;
  }

  const taskId = generateId();
  const task = { id: taskId, status: 'pending' };
  project.tasks[taskId] = task;
  return task;
}

function getTasks(projectId) {
  const project = projectsService.getProjectById(projectId);
  if (!project) {
    return null;
  }

  return project.tasks;
}

function updateTask(projectId, taskId, status) {
  const project = projectsService.getProjectById(projectId);
  if (!project || !project.tasks[taskId]) {
    return null;
  }

  const task = project.tasks[taskId];
  task.status = status;
  return task;
}

module.exports = { createTask, getTasks, updateTask };
